VALUES
  ('police-8b7f1efc-moex-00217', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關性侵害犯罪防治法相關規定敍述，下列何者最正確？', '["犯性騷擾防治法第25條第1項之罪，經判決有罪者準用被害人保護及加害人監控機制", "網路業者違反移除下架性影像者，處新臺幣3萬至30萬元以下罰鍰", "加害人之強制治療期間為3年以下，每年應至少評估一次有無繼續治療之必要", "性侵害犯罪經緩起訴確定者，不必定期向警察機關辦理身分、就學及車籍等相關資料登記、報到"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00218', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '我國刑事訴訟法有關鑑定之規定，下列敘述何者錯誤？', '["鑑定報告屬傳聞證據", "被害人無論是否提起告訴，於偵查中得聲請檢察官選任鑑定人為鑑定", "因經驗而就鑑定事項具有專業能力者，具備鑑定人資格", "檢察官囑託經主管機關認證之機構，所出具鑑定書面報告原則具證據能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00219', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察依「性侵害案件減少被害人重複陳述作業要點」進行詢問被害人，下列敘述何者正確？', '["除顯有保全證據或逮捕現行犯等必要外，應由社工人員先對被害人進行訊前訪視", "被害人為未滿14歲之人時，應經其監護人或法定代理人同意減少被害人重複陳述作業", "詢問過程應全程連續錄影錄音，因錄影錄音造成被害人身心反應無法自由陳述或完全陳述時， 經檢察官或少年法庭法官同意後，得不予錄影錄音", "執行詢（訊）問被害人之錄影錄音啟動時，應注意錄影錄音完整、清晰，為保護隱私，應避免 拍攝到被詢（訊）問人面部"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00220', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關不起訴處分之救濟程序，下列敘述何者最正確？', '["告發人接受不起訴處分書後，得於10日內以書狀敘述不服之理由，經原檢察官向直接上級檢 察署檢察長或檢察總長聲請再議", "原檢察官認為再議之聲請有理由者，應即將該案卷宗及證物送交上級檢察署檢察長或檢察總 長，聲請撤銷其處分", "死刑、無期徒刑或最輕本刑5年以上有期徒刑之案件，因犯罪嫌疑不足，經檢察官為不起訴之 處分，如無得聲請再議之人，原檢察官得依職權逕送直接上級檢察署檢察長或檢察總長再議", "再議聲請人不服再議駁回處分者，得於接受處分書後10日內委任律師提出理由狀，向該管第 一審法院聲請准許提起自訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00221', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察辦理一起販賣毒品案件，持搜索票欲前往嫌疑人住處搜索，在住處附近公園遇見嫌疑人 疑似與另名男子進行毒品交易，兩名男子見員警接近急忙騎乘機車離去，現場留下手機等物證， 司法警察認具相當理由而有立即扣押之必要，下列敘述何者最正確？', '["屬非附隨於搜索之扣押，可逕行扣押並在3日內報告該管檢察官及法院", "屬另案扣押，應請示檢察官同意，始得扣押該手機", "屬非附隨於搜索之扣押，須經檢察官送請法官裁定始得扣押該手機", "本案屬於另案扣押，可逕行扣押無須重新聲請法官審核"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00222', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關偵查中辯護人之權限範圍，下列敘述何者最錯誤？', '["司法警察詢問證人，必要時辯護人得為在場", "司法警察詢問嫌疑人，辯護人得在場以手寫方式抄錄筆記及檢閱證物", "檢察官囑託鑑定進行，必要時辯護人得為在場", "證人指認犯罪嫌疑人時，辯護人得為在場"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00223', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關司法警察進行案件移送與人犯解送作業，下列敘述何者錯誤？', '["少年事件應以報告書將案件移送少年法院", "移送竊盜習慣犯時，若合於宣告保安處分，應於移送書或報告書註明聲請宣告保安處分等意見", "拘提到案之犯罪嫌疑人，若經檢察官核准免予解送，仍應對其執行拍照及按捺指紋等必要措施", "告訴乃論案件逮捕到案之現行犯，若告訴已經撤回，得經檢察官之許可，不予解送"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00224', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '根據憲法法庭111年度憲判字第16號判決，目前司法警察依據刑事訴訟法第205條之2規定以 非侵入性方式採取尿液，受採尿者得於受採取尿液後幾日內，聲請該管法院撤銷之？', '["3", "5", "10", "14"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00225', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察通知嫌疑人甲到場接受詢問，在詢問案件事實時，因疏失未依刑事訴訟法第95條告知 甲得選任辯護人，甲在詢問過程具任意性作出自白，有關該自白證據能力，下列敘述何者正確？', '["絕對排除其證據能力", "依刑事訴訟法第158條之4權衡其證據能力", "因司法警察非出於惡意，且該自白具任意性，故具證據能力", "因該自白具任意性，故具證據能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00226', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察機關偵查中對其移送案件，經檢察官填發偵查指揮書帶同受羈押之被告外出繼續追查贓 證，原則上應於當日幾時前解交檢察官？', '["17時", "18時", "22時", "23時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
